# ══════════════════════════════════════════════════════════════════════════════
# 2. FUNCIONES DE EXTRACCIÓN (CON MARKDOWN)
# ══════════════════════════════════════════════════════════════════════════════
NAV_EXACT = {
    "Síguenos", "LinkedIn", "Instagram", "Facebook", "Youtube", "Twitter",
    "Colaborador TQ", "Portal Médicos", "Gobierno Corporativo", "Pagos Clientes",
    "Así Cambiamos El Mundo", "Trabaja con Nosotros", "Nuestras Marcas",
    "Términos y condiciones", "Políticas de privacidad", "Todos los derechos reservados", 
    "INICIAR SESIÓN", "REGISTRARSE", "Acceso a Journals", "VER TODAS", "ACCEDER", "Buscar", "Cerrar"
}

def extract_text(html: str, section: str) -> str:
    soup = BeautifulSoup(html, "html.parser")
    for tag in soup(["script", "style", "noscript", "nav", "footer", "header", "aside", "form"]):
        tag.decompose()
    
    md_text = markdownify.markdownify(str(soup), heading_style="ATX", strip=['img', 'svg'])
    
    lines = []
    seen = set()
    for line in md_text.splitlines():
        clean_line = line.strip()
        if not clean_line: continue
            
        text_only = re.sub(r'\[([^\]]+)\]\([^\)]+\)', r'\1', clean_line).strip()
        if text_only in NAV_EXACT: continue
            
        if len(text_only) < 4 and not any(c.isdigit() for c in text_only) and not clean_line.startswith("#") and text_only not in ["TQ", "MK"]:
            continue
            
        if clean_line not in seen:
            seen.add(clean_line)
            lines.append(clean_line)
            
    final_text = f"=== SECCION: {section.upper()} ===\n" + "\n".join(lines) + "\n"
    return re.sub(r'\n{3,}', '\n\n', final_text)


# ══════════════════════════════════════════════════════════════════════════════
# 3. LOS MOTORES Y LA EJECUCIÓN (Esto no lo cambiaste, asegúrate de que esté)
# ══════════════════════════════════════════════════════════════════════════════
def get_stealth_driver():
    options = uc.ChromeOptions()
    options.headless = False 
    options.add_argument("--window-size=1920,1080")
    options.add_argument("--ignore-certificate-errors")
    options.add_argument("--allow-running-insecure-content")
    driver = uc.Chrome(options=options, version_main=147)
    driver.set_page_load_timeout(30)
    return driver

def scrape_stealth(driver, url, section):
    try:
        driver.get(url)
        WebDriverWait(driver, 15).until(lambda d: len(d.find_element(By.TAG_NAME, "body").text) > 100)
        for i in range(1, 4):
            driver.execute_script(f"window.scrollTo(0, document.body.scrollHeight * ({i}/4));")
            time.sleep(2)
        return extract_text(driver.page_source, section)
    except Exception as e:
        print(f"      [DEBUG] Error en scrape_stealth: {str(e).split('(')[0].strip()}")
        return "ERROR"

def scrape_requests(session, url, section):
    try:
        r = session.get(url, timeout=20)
        if "Login" in r.url or "login" in r.url: return "REQUIRES_LOGIN"
        if r.status_code == 200: return extract_text(r.text, section)
        return "ERROR"
    except Exception as e:
        print(f"      [DEBUG] Error en scrape_requests: {str(e).split('(')[0].strip()}")
        return "ERROR"

def run_scraping():
    print("\n" + "═" * 68)
    print("   INICIANDO SCRAPING MODO PACIENCIA NINJA (MARKDOWN ENRIQUECIDO)")
    print("═" * 68 + "\n")

    results = {}
    if os.path.exists("raw_data.json"):
        try:
            with open("raw_data.json", "r", encoding="utf-8") as f:
                results = json.load(f)
            print(f"¡Memoria cargada! Se encontraron {len(results)} secciones previas.\n")
        except Exception:
            pass

    total = len(URLS_SELENIUM) + len(URLS_REQUESTS)
    current = 0

    print("Levantando navegador fantasma...")
    driver = get_stealth_driver()
    print("¡Navegador listo!\n")

    for section, url in URLS_SELENIUM.items():
        current += 1
        if section in results and results[section] != "ERROR" and len(results[section]) > 100:
            print(f"[{current:4}/{total}] Saltando: {section} (Ya en memoria)")
            continue

        print(f"[{current:4}/{total}] Extrayendo: {section}...")
        text = scrape_stealth(driver, url, section)
        if text != "ERROR" and len(text) > 100:
            results[section] = text
            print(f"Éxito ({len(text)} chars)")
            with open("raw_data.json", "w", encoding="utf-8") as f: json.dump(results, f, ensure_ascii=False, indent=2)
            time.sleep(random.uniform(15, 25))
        else:
            time.sleep(60)
    driver.quit()

    print("\nPasando a Fase 2: Portal Médico (Requests)...")
    session = requests.Session()
    session.headers.update({"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"})

    for section, url in URLS_REQUESTS.items():
        current += 1
        if section in results and results[section] != "ERROR" and len(results[section]) > 100:
            print(f"[{current:4}/{total}] Saltando: {section} (Ya en memoria)")
            continue

        print(f"[{current:4}/{total}] ⚡ Extrayendo: {section}...")
        text = scrape_requests(session, url, section)
        if text != "ERROR" and len(text) > 100:
            results[section] = text
            print(f" Éxito ({len(text)} chars)")
            with open("raw_data.json", "w", encoding="utf-8") as f: json.dump(results, f, ensure_ascii=False, indent=2)
            time.sleep(random.uniform(8, 15))
        else:
            time.sleep(30)
    print("\n ¡SCRAPING COMPLETADO EN FORMATO MARKDOWN!")

if __name__ == "__main__":
    run_scraping()
